#include <stdio.h>
#include <stdint.h>
#include <string.h>

#define MAX_DRBS_PER_UE 5  // Small for testing
#define DRB_INACTIVE 0
#define DRB_ACTIVE 1

typedef struct {
    uint8_t DRB_active[MAX_DRBS_PER_UE];
} gNB_RRC_UE_t;

// Original version
uint8_t next_available_drb_original(gNB_RRC_UE_t *ue) {
    uint8_t drb_id;
    for (drb_id = 0; drb_id < MAX_DRBS_PER_UE; drb_id++)
        if (ue->DRB_active[drb_id] == DRB_INACTIVE)
            return drb_id + 1;
    return DRB_INACTIVE;
}

// Fixed version
uint8_t next_available_drb_fixed(gNB_RRC_UE_t *ue) {
    uint8_t drb_id;
    for (drb_id = 1; drb_id <= MAX_DRBS_PER_UE; drb_id++)
        if (ue->DRB_active[drb_id - 1] == DRB_INACTIVE)
            return drb_id;
    return DRB_INACTIVE;
}

void print_state(gNB_RRC_UE_t *ue) {
    printf("DRB states: ");
    for (int i = 0; i < MAX_DRBS_PER_UE; i++) {
        printf("%d", ue->DRB_active[i]);
    }
    printf(" (index 0=DRB1, 1=DRB2, etc)\n");
}

int main() {
    gNB_RRC_UE_t ue;
    uint8_t result_original, result_fixed;

    // Test 1: All DRBs inactive
    printf("=== Test 1: All DRBs inactive ===\n");
    memset(ue.DRB_active, DRB_INACTIVE, MAX_DRBS_PER_UE);
    print_state(&ue);
    result_original = next_available_drb_original(&ue);
    result_fixed = next_available_drb_fixed(&ue);
    printf("Original returns: DRB %d, Fixed returns: DRB %d\n", result_original, result_fixed);
    printf("Expected: DRB 1, Match: %s\n\n", 
           (result_original == result_fixed && result_original == 1) ? "YES" : "NO");

    // Test 2: DRB 1 active
    printf("=== Test 2: DRB 1 active ===\n");
    memset(ue.DRB_active, DRB_INACTIVE, MAX_DRBS_PER_UE);
    ue.DRB_active[0] = DRB_ACTIVE;
    print_state(&ue);
    result_original = next_available_drb_original(&ue);
    result_fixed = next_available_drb_fixed(&ue);
    printf("Original returns: DRB %d, Fixed returns: DRB %d\n", result_original, result_fixed);
    printf("Expected: DRB 2, Match: %s\n\n", 
           (result_original == result_fixed && result_original == 2) ? "YES" : "NO");

    // Test 3: DRB 5 (last) active
    printf("=== Test 3: DRB 5 (last) active ===\n");
    memset(ue.DRB_active, DRB_INACTIVE, MAX_DRBS_PER_UE);
    ue.DRB_active[4] = DRB_ACTIVE;
    print_state(&ue);
    result_original = next_available_drb_original(&ue);
    result_fixed = next_available_drb_fixed(&ue);
    printf("Original returns: DRB %d, Fixed returns: DRB %d\n", result_original, result_fixed);
    printf("Expected: DRB 1, Match: %s\n\n", 
           (result_original == result_fixed && result_original == 1) ? "YES" : "NO");

    // Test 4: All DRBs active
    printf("=== Test 4: All DRBs active ===\n");
    memset(ue.DRB_active, DRB_ACTIVE, MAX_DRBS_PER_UE);
    print_state(&ue);
    result_original = next_available_drb_original(&ue);
    result_fixed = next_available_drb_fixed(&ue);
    printf("Original returns: DRB %d, Fixed returns: DRB %d\n", result_original, result_fixed);
    printf("Expected: 0 (DRB_INACTIVE), Match: %s\n\n", 
           (result_original == result_fixed && result_original == 0) ? "YES" : "NO");

    return 0;
}
